proof:
-- Use the fact that `trivialInvo k` is an involution to apply `Equiv.Perm.exists_fixed_point_of_prime`.
have h_inv : Function.Involutive (trivialInvo k) := by
  unfold Involutive;
  unfold trivialInvo; aesop;
-- Since `trivialInvo k` is an involution and `T k` has an odd cardinality, by `Equiv.Perm.exists_fixed_point_of_prime`, there must be a fixed point.
have h_fixed_point_exists : ∃ x : T k, trivialInvo k x = x := by
  convert Equiv.Perm.exists_fixed_point_of_prime (p := 2) _ _ using 1;
  rotate_left;
  exact Fintype.ofFinite _;
  exact 1;
  convert Nat.not_even_iff_odd.mpr ( card_T_odd k ) using 1;
  exact?;
  exact Equiv.ofBijective ( trivialInvo k ) ( h_inv.bijective );
  · exact?;
  · aesop;
exact ⟨ h_fixed_point_exists.choose, h_fixed_point_exists.choose_spec ⟩

